describe('Home integration', () => {
  it('renders page heading and all products', () => {
    render(<Home />);

    expect(screen.getByRole('heading', { level: 1, name: 'Nuestros Productos' })).toBeInTheDocument();
    expect(screen.getByTestId('product-1')).toBeInTheDocument();
    expect(screen.getByTestId('product-2')).toBeInTheDocument();
    expect(screen.getByTestId('product-3')).toBeInTheDocument();
    expect(screen.getByTestId('product-4')).toBeInTheDocument();
  });

  it('admin section is visible for admin role', () => {
    mockAuthUser = { role: 'admin' };
    render(<Home />);

    const adminSection = screen.getByRole('region', { name: 'Acceso admin' });
    expect(adminSection).toBeInTheDocument();
    expect(within(adminSection).getByRole('link', { name: 'Ir al panel de administración' })).toBeInTheDocument();
  });

  it('admin section is NOT visible for client role', () => {
    render(<Home />);

    expect(screen.queryByRole('region', { name: 'Acceso admin' })).not.toBeInTheDocument();
  });

  it('category filter buttons are rendered for each category', () => {
    render(<Home />);

    const filterGroup = screen.getByRole('group', { name: 'Filtrar por categoría' });
    MOCK_CATEGORIES.forEach((cat) => {
      expect(within(filterGroup).getByRole('button', { name: cat })).toBeInTheDocument();
    });
  });

  it('clicking a category filter shows only matching products', async () => {
    const user = userEvent.setup();
    render(<Home />);

    await user.click(screen.getByRole('button', { name: 'Electrónica', pressed: false }));

    expect(screen.getByTestId('product-1')).toBeInTheDocument();
    expect(screen.getByTestId('product-4')).toBeInTheDocument();
    expect(screen.queryByTestId('product-2')).not.toBeInTheDocument();
    expect(screen.queryByTestId('product-3')).not.toBeInTheDocument();
  });

  it('active category button has aria-pressed=true', async () => {
    const user = userEvent.setup();
    render(<Home />);

    const electronicaBtn = screen.getByRole('button', { name: 'Electrónica' });
    expect(electronicaBtn).toHaveAttribute('aria-pressed', 'false');

    await user.click(electronicaBtn);
    expect(electronicaBtn).toHaveAttribute('aria-pressed', 'true');
  });

  it('search input filters products by name', async () => {
    const user = userEvent.setup();
    render(<Home />);

    await user.type(screen.getByRole('searchbox'), 'Zapatillas');

    // Wait for debounce (250ms) — product-2 should appear and product-1 should disappear
    await waitFor(() => {
      expect(screen.getByTestId('product-2')).toBeInTheDocument();
      expect(screen.queryByTestId('product-1')).not.toBeInTheDocument();
    });
  });

  it('search is accent-insensitive for product text', async () => {
    const user = userEvent.setup();
    render(<Home />);

    await user.type(screen.getByRole('searchbox'), 'inalambricos');

    await waitFor(() => {
      expect(screen.getByTestId('product-1')).toBeInTheDocument();
      expect(screen.queryByTestId('product-2')).not.toBeInTheDocument();
    });
  });

  it('clear search button appears with text and clears results when clicked', async () => {
    const user = userEvent.setup();
    render(<Home />);

    await user.type(screen.getByRole('searchbox'), 'Zapatillas');

    const clearSearchButton = await screen.findByRole('button', { name: 'Limpiar búsqueda' });
    expect(clearSearchButton).toBeInTheDocument();

    await user.click(clearSearchButton);

    await waitFor(() => {
      expect(screen.queryByRole('button', { name: 'Limpiar búsqueda' })).not.toBeInTheDocument();
      expect(screen.getByTestId('product-1')).toBeInTheDocument();
      expect(screen.getByTestId('product-2')).toBeInTheDocument();
      expect(screen.getByTestId('product-3')).toBeInTheDocument();
      expect(screen.getByTestId('product-4')).toBeInTheDocument();
    });
  });

  it('pressing Escape in searchbox clears current search', async () => {
    const user = userEvent.setup();
    render(<Home />);

    const searchbox = screen.getByRole('searchbox');
    await user.type(searchbox, 'Zapatillas');

    await waitFor(() => {
      expect(screen.getByTestId('product-2')).toBeInTheDocument();
      expect(screen.queryByTestId('product-1')).not.toBeInTheDocument();
    });

    await user.click(searchbox);
    await user.keyboard('{Escape}');

    await waitFor(() => {
      expect(searchbox).toHaveValue('');
      expect(screen.getByTestId('product-1')).toBeInTheDocument();
      expect(screen.getByTestId('product-2')).toBeInTheDocument();
      expect(screen.getByTestId('product-3')).toBeInTheDocument();
      expect(screen.getByTestId('product-4')).toBeInTheDocument();
    });

    expect(searchbox).toHaveAttribute('aria-describedby', 'home-search-shortcut');
    expect(screen.getByText('Atajos: / para enfocar búsqueda y Escape para limpiar.')).toBeInTheDocument();
  });

  it('pressing slash focuses searchbox when focus is outside input fields', async () => {
    const user = userEvent.setup();
    render(<Home />);

    const heading = screen.getByRole('heading', { level: 1, name: 'Nuestros Productos' });
    const searchbox = screen.getByRole('searchbox');

    heading.focus();
    expect(searchbox).not.toHaveFocus();

    await user.keyboard('/');

    expect(searchbox).toHaveFocus();
  });

  it('clear filters button appears when filters are active and clears them', async () => {
    const user = userEvent.setup();
    render(<Home />);

    // No active filters — button should not be visible
    expect(screen.queryByRole('button', { name: 'Limpiar filtros' })).not.toBeInTheDocument();

    // Activate a category filter
    await user.click(screen.getByRole('button', { name: 'Deportes' }));
    const clearBtn = screen.getByRole('button', { name: 'Limpiar filtros' });
    expect(clearBtn).toBeInTheDocument();

    // Clear filters — should show all products again
    await user.click(clearBtn);
    expect(screen.queryByRole('button', { name: 'Limpiar filtros' })).not.toBeInTheDocument();
    expect(screen.getByTestId('product-1')).toBeInTheDocument();
    expect(screen.getByTestId('product-2')).toBeInTheDocument();
    expect(screen.getByTestId('product-3')).toBeInTheDocument();
  });

  it('empty state is shown when search matches nothing', async () => {
    const user = userEvent.setup();
    render(<Home />);

    await user.type(screen.getByRole('searchbox'), 'xyznonexistentproduct');

    await screen.findByText('No hay resultados');
    const noResultsHeading = screen.getByText('No hay resultados');
    expect(noResultsHeading).toBeInTheDocument();
    expect(noResultsHeading).toHaveFocus();
  });

  it('announces results and current page in a polite live region', async () => {
    const user = userEvent.setup();
    render(<Home />);

    expect(screen.getByRole('status')).toHaveTextContent('4 resultados');
    expect(screen.getByRole('status')).toHaveTextContent('Página 1 de 1');

    await user.type(screen.getByRole('searchbox'), 'Zapatillas');

    await waitFor(() => {
      expect(screen.getByRole('status')).toHaveTextContent('1 resultado');
      expect(screen.getByRole('status')).toHaveTextContent('Página 1 de 1');
    });
  });

  it('sort select changes product order (price ascending)', async () => {
    const user = userEvent.setup();
    render(<Home />);

    const sortSelect = screen.getByRole('combobox');
    await user.selectOptions(sortSelect, 'price-asc');

    const cards = screen.getAllByTestId(/^product-/);
    // Cheapest ($44.99 Mochila) should be first
    expect(cards[0]).toHaveAttribute('data-testid', 'product-3');
  });
});
